#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int data;
    struct Node* next;
} Node;

int getLength(Node* head) {
    int cnt = 0;
    while (head) {
        ++cnt;
        head = head->next;
    }
    return cnt;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        Node *head = NULL, *tail = NULL;
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            Node* nd = (Node*)malloc(sizeof(Node));
            nd->data = x; nd->next = NULL;
            if (!head) head = tail = nd; else { tail->next = nd; tail = nd; }
        }
        printf("%d\n", getLength(head));
        while (head) { Node* tmp = head; head = head->next; free(tmp); }
    }
    return 0;
}

