code.Java:
import java.io.*;
import java.util.*;

class Node {
    int data;
    Node next;
    Node(int d) { data = d; next = null; }
}

public class Main {
    static int getLength(Node head) {
        int cnt = 0;
        while (head != null) {
            cnt++;
            head = head.next;
        }
        return cnt;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null || line.isEmpty()) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            int N = Integer.parseInt(br.readLine().trim());
            Node head = null, tail = null;
            if (N > 0) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                for (int i = 0; i < N; ++i) {
                    int val = Integer.parseInt(st.nextToken());
                    Node nd = new Node(val);
                    if (head == null) head = tail = nd; else { tail.next = nd; tail = nd; }
                }
            } else {
                // consume the possibly empty line representing the list values
                br.readLine();
            }
            out.append(getLength(head)).append('\n');
        }
        System.out.print(out.toString());
    }
}

code.Python3:
import sys

def getLength(head):
    cnt = 0
    while head:
        cnt += 1
        head = head.next
    return cnt

class Node:
    __slots__ = ('data', 'next')
    def __init__(self, data):
        self.data = data
        self.next = None

def main():
    data = sys.stdin.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        head = tail = None
        for _ in range(N):
            val = int(next(it))
            nd = Node(val)
            if head is None:
                head = tail = nd
            else:
                tail.next = nd
                tail = nd
        out.append(str(getLength(head)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

